// 요청 바디에서 아이디/비밀번호 추출
const body = $input.first().json.body || {};
const userId = body.userId || '';
const password = body.password || '';

if (!userId || !password) {
  return [{ json: { success: false, error: '아이디와 비밀번호를 입력해주세요' } }];
}

return [{ json: { userId, password } }];

// 회원 조회 결과 처리 + 간이 JWT 생성
// 주의: 메이크샵 회원 API는 비밀번호 검증을 직접 할 수 없음
// 따라서 회원 존재 여부로 1차 확인 후 앱 자체 세션 관리

const response = $input.first().json;
let members = [];
if (response && typeof response === 'object' && !Array.isArray(response)) {
  members = Object.values(response);
}

if (members.length === 0) {
  return [{ json: { success: false, error: '존재하지 않는 회원입니다' } }];
}

const m = members[0];

// 간이 토큰 생성 (Base64 인코딩, 실제 운영 시 crypto 모듈로 교체)
const payload = JSON.stringify({
  userId: m.userid || m.id || '',
  name: m.name || '',
  email: m.email || '',
  phone: m.mobile || '',
  grade: m.group_name || '',
  iat: Date.now(),
  exp: Date.now() + 7 * 24 * 60 * 60 * 1000 // 7일
});
const token = Buffer.from(payload).toString('base64');

const user = {
  id: m.userid || m.id || '',
  name: m.name || '',
  email: m.email || '',
  phone: m.mobile || '',
  isPartner: (m.group_name || '').includes('강사') || (m.group_no || '') !== '1',
  partnerGrade: null,
};

// 파트너 등급 매핑
const groupName = (m.group_name || '').toUpperCase();
if (groupName.includes('AMBASSADOR') || groupName.includes('앰배서더')) user.partnerGrade = 'AMBASSADOR';
else if (groupName.includes('ATELIER') || groupName.includes('아뜰리에')) user.partnerGrade = 'ATELIER';
else if (groupName.includes('GARDEN') || groupName.includes('가든')) user.partnerGrade = 'GARDEN';
else if (groupName.includes('BLOOM') || groupName.includes('블룸')) user.partnerGrade = 'BLOOM';

return [{ json: { success: true, data: { token, user } } }];
